const data = result?.data;

{result?.status === "success" && data && (
  <div>
    <h3>F1 Score: {(data?.f1_score * 100).toFixed(2)}%</h3>

    <tbody>
      {data?.predictions?.map((pred, i) => (
        <tr key={i}>
          <td>{i}</td>
          <td>{data?.actual?.[i]}</td>
          <td>{pred}</td>
          <td>{data?.clusters?.[i]}</td>
        </tr>
      ))}
    </tbody>
  </div>
)}
